// ============================================================
// 🧠 RESEARCH LOOP ORCHESTRATOR
// ============================================================
// Este Code node ejecuta el bucle completo de investigación:
//   SEARCH → FETCH → ANALYZE → DECIDE → (loop back)
// Usa Tavily para buscar, fetch para descargar, y Ollama
// (Mistral Nemo) para analizar y decidir próximos pasos.
// ============================================================

const topic = $input.first().json.topic;
const maxIterations = $input.first().json.maxIterations || 5;
const tavilyApiKey = $input.first().json.tavilyApiKey;
const ollamaBaseUrl = $input.first().json.ollamaBaseUrl || 'http://ollama:11434';
const modelName = $input.first().json.modelName || 'mistral-nemo:latest';

// Almacén de todos los hallazgos
let allFindings = [];
// Consulta inicial = tema del usuario
let currentQuery = topic;
// Historial de consultas para no repetir
const queryHistory = [];

// -------------------------------------------------------
// FUNCIÓN: Buscar con Tavily API
// -------------------------------------------------------
async function searchTavily(query, apiKey) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.tavily.com/search',
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json'
      },
      body: {
        query: query,
        search_depth: 'advanced',
        max_results: 5,
        include_answer: true,
        include_raw_content: false,
        topic: 'general'
      },
      json: true
    });
    return response;
  } catch (error) {
    console.error('❌ Error en Tavily search:', error.message);
    return { results: [], answer: null };
  }
}

// -------------------------------------------------------
// FUNCIÓN: Descargar contenido de una URL
// -------------------------------------------------------
async function fetchUrlContent(url) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      timeout: 10000,
      headers: {
        'User-Agent': 'Mozilla/5.0 (ResearchBot/1.0)'
      },
      json: false,
      returnFullResponse: true
    });
    // Extraer texto del HTML (limpieza básica)
    let text = response.body || '';
    // Quitar tags HTML básicos
    text = text.replace(/<script[\s\S]*?<\/script>/gi, '');
    text = text.replace(/<style[\s\S]*?<\/style>/gi, '');
    text = text.replace(/<[^>]+>/g, ' ');
    text = text.replace(/\s+/g, ' ').trim();
    // Limitar a ~4000 caracteres para no saturar a Ollama
    return text.substring(0, 4000);
  } catch (error) {
    console.error('❌ Error fetching URL:', url, error.message);
    return `[No se pudo descargar: ${error.message}]`;
  }
}

// -------------------------------------------------------
// FUNCIÓN: Analizar con Ollama (Mistral Nemo)
// -------------------------------------------------------
async function analyzeWithOllama(prompt, systemPrompt) {
  try {
    const fullPrompt = systemPrompt 
      ? `${systemPrompt}\n\n${prompt}`
      : prompt;

    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: `${ollamaBaseUrl}/api/generate`,
      body: {
        model: modelName,
        prompt: fullPrompt,
        stream: false,
        options: {
          temperature: 0.3,
          num_predict: 1024
        }
      },
      json: true
    });
    return response.response || '';
  } catch (error) {
    console.error('❌ Error en Ollama:', error.message);
    return `[Error de análisis: ${error.message}]`;
  }
}

// -------------------------------------------------------
// FUNCIÓN: Decidir si continuar y generar siguiente query
// -------------------------------------------------------
async function decideNextStep(findings, topic, iteration) {
  const decisionPrompt = `Eres un agente de investigación. Analiza los hallazgos acumulados y decide si se necesita más investigación.

TEMA PRINCIPAL: "${topic}"
ITERACIÓN ACTUAL: ${iteration + 1}

HALLAZGOS ACUMULADOS:
${JSON.stringify(findings.slice(-5), null, 2)}

INSTRUCCIONES:
- Si la información es suficiente y completa, responde EXACTAMENTE: "FINALIZAR: <breve razón>"
- Si falta información relevante, responde EXACTAMENTE: "CONTINUAR: <nueva consulta específica>"
- La nueva consulta debe ser concreta y enfocada en lo que falta por investigar.
- NO repitas consultas ya hechas. Sé creativo con ángulos nuevos.

Tu decisión:`;

  const decision = await analyzeWithOllama(decisionPrompt, null);
  return decision.trim();
}

// -------------------------------------------------------
// 🌀 BUCLE PRINCIPAL DE INVESTIGACIÓN
// -------------------------------------------------------
console.log(`🔍 Iniciando investigación sobre: "${topic}"`);
console.log(`🔄 Máximo de iteraciones: ${maxIterations}`);

for (let i = 0; i < maxIterations; i++) {
  console.log(`\n📍 === ITERACIÓN ${i + 1}/${maxIterations} ===`);
  console.log(`🔎 Consulta: "${currentQuery}"`);

  queryHistory.push(currentQuery);

  // ---------- PASO 1: BUSCAR ----------
  console.log('🌐 Buscando con Tavily...');
  const searchResponse = await searchTavily(currentQuery, tavilyApiKey);

  if (!searchResponse.results || searchResponse.results.length === 0) {
    console.log('⚠️  Sin resultados. Generando nueva consulta...');
    const nextQuery = await analyzeWithOllama(
      `No se encontraron resultados para "${currentQuery}" sobre el tema "${topic}". Genera una nueva consulta de búsqueda más efectiva.`,
      'Eres un experto en formular consultas de búsqueda. Responde SOLO con la nueva consulta, sin explicaciones.'
    );
    currentQuery = nextQuery.trim();
    continue;
  }

  // Mostrar answer de Tavily si existe
  if (searchResponse.answer) {
    console.log(`💡 Tavily Answer: ${searchResponse.answer.substring(0, 200)}...`);
    allFindings.push({
      type: 'tavily_answer',
      content: searchResponse.answer,
      iteration: i + 1,
      query: currentQuery
    });
  }

  // ---------- PASO 2: DESCARGAR Y ANALIZAR cada resultado ----------
  const topResults = searchResponse.results.slice(0, 3);

  for (let j = 0; j < topResults.length; j++) {
    const result = topResults[j];
    console.log(`  📄 [${j+1}/${topResults.length}] Fetching: ${result.title?.substring(0, 80)}`);

    // Descargar contenido
    const rawContent = await fetchUrlContent(result.url);

    // Si el contenido es muy corto, usar el snippet de Tavily
    const contentToAnalyze = rawContent.length > 100 ? rawContent : (result.content || '');

    // ---------- PASO 3: ANALIZAR con Mistral Nemo ----------
    const analysisPrompt = `Analiza el siguiente contenido relacionado con el tema "${topic}".

TÍTULO: ${result.title}
URL: ${result.url}

CONTENIDO:
${contentToAnalyze}

INSTRUCCIONES:
Extrae SOLO la información más relevante y novedosa para el tema "${topic}".
Responde en formato JSON con:
{
  "key_facts": ["hecho 1", "hecho 2", ...],
  "relevance": "alta/media/baja",
  "summary": "resumen en 2-3 frases",
  "new_angles": ["nuevo ángulo de investigación 1", ...]
}`;

    const analysis = await analyzeWithOllama(
      analysisPrompt,
      'Eres un asistente de investigación experto. Analizas contenido web y extraes información clave de forma concisa y estructurada. Responde SIEMPRE en JSON válido.'
    );

    // Intentar parsear el JSON, si falla guardar como texto
    let parsedAnalysis;
    try {
      // Limpiar posibles markdown code blocks
      const cleanJson = analysis.replace(/```json\n?|```\n?/g, '').trim();
      parsedAnalysis = JSON.parse(cleanJson);
    } catch (e) {
      parsedAnalysis = { raw_analysis: analysis };
    }

    allFindings.push({
      type: 'web_analysis',
      title: result.title,
      url: result.url,
      analysis: parsedAnalysis,
      iteration: i + 1,
      query: currentQuery
    });

    console.log(`  ✅ Analizado: ${result.title?.substring(0, 60)}`);
  }

  // ---------- PASO 4: DECIDIR si continuar ----------
  console.log('🤔 Decidiendo próximo paso...');
  const decision = await decideNextStep(allFindings, topic, i);
  console.log(`  📋 Decisión: ${decision.substring(0, 150)}`);

  if (decision.startsWith('FINALIZAR')) {
    console.log('✅ Investigación completada por decisión del modelo.');
    break;
  } else if (decision.startsWith('CONTINUAR')) {
    const nextQuery = decision.replace(/^CONTINUAR:\s*/i, '').trim();
    // Evitar repetir consultas
    if (queryHistory.some(q => q.toLowerCase() === nextQuery.toLowerCase())) {
      console.log('⚠️  Consulta repetida, variando...');
      currentQuery = `${nextQuery} (ángulo alternativo)`;
    } else {
      currentQuery = nextQuery;
    }
  } else {
    // Si el modelo no siguió el formato, generar nueva consulta automáticamente
    const fallbackQuery = await analyzeWithOllama(
      `Basado en todo lo investigado sobre "${topic}", genera UNA nueva consulta de búsqueda para profundizar en un aspecto que falte. Responde SOLO con la consulta.`,
      'Eres un experto en investigación. Generas consultas de búsqueda concisas y efectivas.'
    );
    currentQuery = fallbackQuery.trim();
  }
}

console.log(`\n🏁 Investigación finalizada. Total hallazgos: ${allFindings.length}`);

// -------------------------------------------------------
// RESULTADO FINAL
// -------------------------------------------------------
return [{
  json: {
    topic: topic,
    totalIterations: Math.min(queryHistory.length, maxIterations),
    totalFindings: allFindings.length,
    queriesUsed: queryHistory,
    findings: allFindings,
    completedAt: new Date().toISOString()
  }
}];
